import React from 'react';
import { View, StyleSheet, ScrollView, Dimensions } from 'react-native';
import { Text, Card } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';

const { width } = Dimensions.get('window');

export default function FarmerDashboardScreen() {
  const stats = {
    totalEarnings: 25000,
    pendingOrders: 8,
    activeProducts: 12,
    completedOrders: 45,
  };

  const recentOrders = [
    {
      id: 1,
      buyer: 'Rahul Mehta',
      product: 'Fresh Tomatoes',
      quantity: 5,
      amount: 200,
      status: 'Pending',
    },
    {
      id: 2,
      buyer: 'Sneha Patel',
      product: 'Organic Spinach',
      quantity: 3,
      amount: 90,
      status: 'Accepted',
    },
  ];

  return (
    <ScrollView style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.greeting}>Welcome Back! 🌾</Text>
        <Text style={styles.headerTitle}>Your Farm Dashboard</Text>
      </View>

      {/* Stats Cards */}
      <View style={styles.statsContainer}>
        <View style={styles.statsRow}>
          <Card style={[styles.statCard, { backgroundColor: '#E8F5E9' }]}>
            <View style={styles.statContent}>
              <Icon name="currency-inr" size={30} color="#2E7D32" />
              <Text style={styles.statValue}>₹{stats.totalEarnings}</Text>
              <Text style={styles.statLabel}>Total Earnings</Text>
            </View>
          </Card>

          <Card style={[styles.statCard, { backgroundColor: '#FFF3E0' }]}>
            <View style={styles.statContent}>
              <Icon name="clock-outline" size={30} color="#F57C00" />
              <Text style={styles.statValue}>{stats.pendingOrders}</Text>
              <Text style={styles.statLabel}>Pending Orders</Text>
            </View>
          </Card>
        </View>

        <View style={styles.statsRow}>
          <Card style={[styles.statCard, { backgroundColor: '#E3F2FD' }]}>
            <View style={styles.statContent}>
              <Icon name="package-variant" size={30} color="#1976D2" />
              <Text style={styles.statValue}>{stats.activeProducts}</Text>
              <Text style={styles.statLabel}>Active Products</Text>
            </View>
          </Card>

          <Card style={[styles.statCard, { backgroundColor: '#F3E5F5' }]}>
            <View style={styles.statContent}>
              <Icon name="check-circle" size={30} color="#7B1FA2" />
              <Text style={styles.statValue}>{stats.completedOrders}</Text>
              <Text style={styles.statLabel}>Completed</Text>
            </View>
          </Card>
        </View>
      </View>

      {/* Recent Orders */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Recent Orders</Text>
        {recentOrders.map((order) => (
          <Card key={order.id} style={styles.orderCard}>
            <View style={styles.orderContent}>
              <View style={styles.orderInfo}>
                <Text style={styles.orderBuyer}>{order.buyer}</Text>
                <Text style={styles.orderProduct}>
                  {order.product} - {order.quantity} kg
                </Text>
                <Text style={styles.orderAmount}>₹{order.amount}</Text>
              </View>
              <View
                style={[
                  styles.statusBadge,
                  order.status === 'Pending'
                    ? { backgroundColor: '#FFF3E0' }
                    : { backgroundColor: '#E8F5E9' },
                ]}
              >
                <Text
                  style={[
                    styles.statusText,
                    order.status === 'Pending'
                      ? { color: '#F57C00' }
                      : { color: '#2E7D32' },
                  ]}
                >
                  {order.status}
                </Text>
              </View>
            </View>
          </Card>
        ))}
      </View>

      {/* Quick Actions */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Quick Actions</Text>
        <View style={styles.actionsRow}>
          <Card style={styles.actionCard}>
            <View style={styles.actionContent}>
              <Icon name="plus-circle" size={40} color="#2E7D32" />
              <Text style={styles.actionText}>Add Product</Text>
            </View>
          </Card>

          <Card style={styles.actionCard}>
            <View style={styles.actionContent}>
              <Icon name="chart-line" size={40} color="#1976D2" />
              <Text style={styles.actionText}>View Analytics</Text>
            </View>
          </Card>
        </View>
      </View>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  header: {
    backgroundColor: '#fff',
    padding: 20,
    paddingTop: 60,
    paddingBottom: 30,
  },
  greeting: {
    fontSize: 16,
    color: '#666',
  },
  headerTitle: {
    fontSize: 24,
    fontWeight: 'bold',
    color: '#333',
    marginTop: 5,
  },
  statsContainer: {
    padding: 15,
  },
  statsRow: {
    flexDirection: 'row',
    marginBottom: 15,
  },
  statCard: {
    flex: 1,
    marginHorizontal: 5,
    elevation: 2,
  },
  statContent: {
    padding: 20,
    alignItems: 'center',
  },
  statValue: {
    fontSize: 24,
    fontWeight: 'bold',
    marginTop: 10,
    color: '#333',
  },
  statLabel: {
    fontSize: 12,
    color: '#666',
    marginTop: 5,
    textAlign: 'center',
  },
  section: {
    marginTop: 10,
    marginBottom: 20,
  },
  sectionTitle: {
    fontSize: 18,
    fontWeight: 'bold',
    color: '#333',
    paddingHorizontal: 20,
    marginBottom: 15,
  },
  orderCard: {
    marginHorizontal: 20,
    marginBottom: 10,
    elevation: 2,
  },
  orderContent: {
    flexDirection: 'row',
    padding: 15,
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  orderInfo: {
    flex: 1,
  },
  orderBuyer: {
    fontSize: 16,
    fontWeight: '600',
    color: '#333',
  },
  orderProduct: {
    fontSize: 14,
    color: '#666',
    marginTop: 5,
  },
  orderAmount: {
    fontSize: 16,
    fontWeight: 'bold',
    color: '#2E7D32',
    marginTop: 5,
  },
  statusBadge: {
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 12,
  },
  statusText: {
    fontSize: 12,
    fontWeight: '600',
  },
  actionsRow: {
    flexDirection: 'row',
    paddingHorizontal: 15,
  },
  actionCard: {
    flex: 1,
    marginHorizontal: 5,
    elevation: 2,
  },
  actionContent: {
    padding: 20,
    alignItems: 'center',
  },
  actionText: {
    fontSize: 14,
    fontWeight: '600',
    color: '#333',
    marginTop: 10,
    textAlign: 'center',
  },
});
